# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

from flask import Flask, request, jsonify
import json
from web3 import Web3, HTTPProvider

app = Flask(__name__)
web3 = Web3(HTTPProvider('http://localhost:8545'))  # Replace with your node url

@app.route('/verify', methods=['POST'])
def verify_signature():
    data = request.get_json()
    
    try:
        message = data["message"]
        signature = data["signature"]
        
        if not web3.isAddress(data["address"]):  # Checking if the address is a valid Ethereum address
            return jsonify({"error": "Invalid Ethereum Address"}), 400
        
        signer = web3.eth.account.recoverMessage(message, signature=signature)
        
        if signer.lower() == data["address"].lower():  # Comparing lowercase version for case insensitivity
            return jsonify({"success": "Signature verified successfully!"}), 200
            
    except Exception as e:
        return jsonify({"error": str(e)}), 500
        
if __name__ == '__main__':
    app.run()